import { useEffect, useState } from "react";
import API from "../services/api";

export default function BiodataList() {
  const [data, setData] = useState([]);

  useEffect(() => {
    API.get("/biodata/me").then(res => {
      setData(res.data);
    });
  }, []);

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.title}>My Biodata</h2>

        {data.length === 0 && (
          <p style={styles.empty}>No biodata found</p>
        )}

        {data.map(item => (
  <div key={item._id} style={styles.card}>
    <p style={styles.name}>{item.fullName}</p>

    <p style={styles.text}>Email: {item.email}</p>
    <p style={styles.text}>Phone: {item.phone}</p>
    <p style={styles.text}>DOB: {item.dob}</p>
    <p style={styles.text}>Gender: {item.gender}</p>
    <p style={styles.text}>Address: {item.address}</p>

    {item.image && (
      <img
        src={`http://localhost:5000/uploads/${item.image}`}
        style={styles.image}
        alt="profile"
      />
    )}
  </div>
))}
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "#f4f6f8",
    display: "flex",
    justifyContent: "center",
    alignItems: "center"
  },
  
  container: {
    width: "400px",
    background: "#fff",
    padding: "25px",
    borderRadius: "12px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)"
  },
  title: {
    textAlign: "center",
    marginBottom: "20px"
  },
  empty: {
    textAlign: "center",
    color: "#888"
  },
  card: {
    background: "#f9f9f9",
    padding: "15px",
    marginBottom: "12px",
    borderRadius: "8px",
    boxShadow: "0 2px 6px rgba(0,0,0,0.05)",
    textAlign: "center"
  },
  name: {
    fontWeight: "bold",
    marginBottom: "10px"
  },
  image: {
    width: "100px",
    borderRadius: "8px"
  }
};
